import numpy as np
def pairwise_distances(X):
    X = np.asarray(X)
    m = X.shape[0]
    D = np.zeros((m, m))
    for i in range(m):
        for j in range(m):
            D[i, j] = np.sqrt(np.sum((X[i] - X[j]) ** 2))
    return D

